class Admin::ReportsController < ApplicationController
  before_action :authenticate_user!
  before_action :require_admin!

  # Predefined report definitions - the ONLY queries that can run
  REPORT_DEFINITIONS = {
    "user_signups" => {
      description: "User signups over time",
      query: ->(params) {
        User.where(created_at: parse_date_range(params))
            .group_by_day(:created_at)
            .count
      }
    },
    "revenue_by_product" => {
      description: "Revenue grouped by product",
      query: ->(params) {
        Order.joins(:product)
             .where(created_at: parse_date_range(params))
             .group("products.name")
             .sum(:total_amount)
      }
    },
    "active_users" => {
      description: "Users with recent activity",
      query: ->(params) {
        User.joins(:sessions)
            .where(sessions: { created_at: parse_date_range(params) })
            .distinct
            .select(:id, :email, :name, :created_at)
      }
    },
    "top_customers" => {
      description: "Top customers by order value",
      query: ->(params) {
        limit = [params.fetch(:limit, 25).to_i, 100].min
        User.joins(:orders)
            .where(orders: { created_at: parse_date_range(params) })
            .group(:id)
            .select("users.id, users.email, users.name, SUM(orders.total_amount) as total_spent, COUNT(orders.id) as order_count")
            .order("total_spent DESC")
