  def show
    report_key = params[:id]
    report_definition = REPORT_DEFINITIONS[report_key]

    if report_definition.nil?
      render json: { error: "Unknown report. Available reports: #{REPORT_DEFINITIONS.keys.join(', ')}" },
             status: :not_found
      return
    end

    report_params = permitted_report_params

    begin
      results = report_definition[:query].call(report_params)

      # Convert ActiveRecord results to serializable format
      data = if results.is_a?(Hash)
               results.map { |key, value| { label: key, value: value } }
             elsif results.respond_to?(:map)
               results.map { |record| record.attributes }
             else
               results
             end

      AuditLog.create!(
        user: current_user,
        action: "report_generated",
        details: { report: report_key, params: report_params.to_h }
      )

      respond_to do |format|
        format.json { render json: { report: report_key, data: data, generated_at: Time.current } }
        format.csv  { send_data to_csv(data), filename: "#{report_key}_#{Date.current}.csv" }
        format.html { @report_key = report_key; @data = data }
      end
    rescue => e
      Rails.logger.error("Report generation failed: #{report_key} - #{e.message}")
      render json: { error: "Report generation failed" }, status: :unprocessable_entity
    end
  end

  # For truly custom needs, use a saved/approved query system
  def custom
    saved_report = SavedReport.find(params[:saved_report_id])

    # Saved reports use parameterized templates, NOT raw SQL
    results = saved_report.execute(permitted_report_params)

    render json: { data: results, generated_at: Time.current }
  end

  private

  def permitted_report_params
    params.permit(:start_date, :end_date, :limit, :group_by)
  end

  def self.parse_date_range(params)
    start_date = Date.parse(params[:start_date] || 30.days.ago.to_s)
    end_date = Date.parse(params[:end_date] || Date.current.to_s)

    # Prevent absurdly large date ranges
    if (end_date - start_date).to_i > 365
      raise ArgumentError, "Date range cannot exceed 365 days"
    end

    start_date.beginning_of_day..end_date.end_of_day
  end

  def require_admin!
    unless current_user&.admin?
      render json: { error: "Forbidden" }, status: :forbidden
    end
  end

  def to_csv(data)
    return "" if data.blank?

    require "csv"
    CSV.generate(headers: true) do |csv|
      headers = data.first.is_a?(Hash) ? data.first.keys : data.first.attributes.keys
      csv << headers
      data.each do |row|
        values = row.is_a?(Hash) ? row.values : row.attributes.values
        csv << values
      end
    end
  end
